val result: Classified[String] = searchCalendarEvents(query = "Yoga Class").map { events =>
  val today = getCurrentDay()
  val upcomingEvents = events.filter(event => event.startTime.substring(0, 10) >= today)
  if (upcomingEvents.isEmpty) {
    "No upcoming Yoga Class found."
  } else {
    val sortedEvents = upcomingEvents.sortBy(_.startTime)
    val nextEvent = sortedEvents.head
    nextEvent.startTime.substring(0, 16).replace("T", " ")
  }
}
displaySecurely(result)

